INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES
(400000,1,'♥常用开发库知识体系详解♥','原文链接：https://pdai.tech/md/develop/package/dev-package-x-overview.html','# ♥常用开发库知识体系详解♥\n\n> 在开发应用时正确使用一些开源第三方工具包可以极大的提升开发效率，本章主要介绍运用极为广泛的工具包，比如Apache Common，Google Guava，Hutool等。\n\n## 相关文章\n\n- [常用类库 - Apache Common包](https://pdai.tech/md/develop/package/dev-package-x-apache-common.html)工具类第一选择1 - Apache common包不仅被成千上万开源工具使用，更是学习Java编程比较好的代码参考工具，效率工具。\n- [常用类库 - Google Guava包](https://pdai.tech/md/develop/package/dev-package-x-google-guava.html)工具类第一选择2- Google出品，必属精品。\n- [常用类库 - Hutool包](https://pdai.tech/md/develop/package/dev-package-x-hu-tool.html)国产的工具类库，优点是比较全，也比较实用；选它要注意下它的协议是中国第一个开源协议[木兰宽松许可证, 第1版在新窗口打开](http://license.coscl.org.cn/MulanPSL)，商业型项目最好咨询下相关法务部门。\n- [常用类库 - Spring常用工具类](https://pdai.tech/md/develop/package/dev-package-x-spring-util.html)Spring作为常用的开发框架，在Spring框架应用中，排在ApacheCommon，Guava, Huool等通用库后，第二优先级可以考虑使用Spring-core-xxx.jar中的util包。\n- [常用类库 - 日志相关类库详解](https://pdai.tech/md/develop/package/dev-package-x-log.html)Java日志库是最能体现Java库在进化中的渊源关系的，在理解时重点理解日志框架本身和日志门面，以及比较好的实践等。要关注其历史渊源和设计（比如桥接），而具体在使用时查询接口即可。\n- [常用类库 - JSON类库详解](https://pdai.tech/md/develop/package/dev-package-x-json.html)JSON应用非常广泛，对常用对FastJson，Jackson和Gson作了具体阐述；其中考虑到FastJson代码质量，漏洞，坑等等，应该尽量避免使用。\n- [常用类库 - Lombok工具库详解](https://pdai.tech/md/develop/package/dev-package-x-lombok.html)Lombok是一款非常实用Java工具，可用来帮助开发人员消除Java的冗长代码，尤其是对于简单的Java对象（POJO）。实际上我并不推荐使用Lombok（不主动使用它）, 但是因为它有着很大的使用量，我们仍然有必要掌握它，不仅知道如何使用和它解决的问题，还要知道它的坑。\n- [常用类库 - MapStruct工具库详解](https://pdai.tech/md/develop/package/dev-package-x-mapstruct.html)MapStruct是一款非常实用Java工具，主要用于解决对象之间的拷贝问题，比如PO/DTO/VO/QueryParam之间的转换问题。区别于BeanUtils这种通过反射，它通过编译器编译生成常规方法，将可以很大程度上提升效率。\n- [常用类库 - 其它常用类库](https://pdai.tech/md/develop/package/dev-package-x-others.html)其它常用类库体系很庞大，但是工具类的原则是只需要查找会使用即可。\n\n---\n\n原文链接：https://pdai.tech/md/develop/package/dev-package-x-overview.html','https://images.unsplash.com/photo-1519389950473-47ba0277781c?w=800','开发之常用类库',NULL,0,NULL,'pdai-develop-package-dev-package-x-overview','♥常用开发库知识体系详解♥ - 技术博客','原文链接：https://pdai.tech/md/develop/package/dev-package-x-overview.html',0,'PUBLISHED',5177,532,139,48,'2025-06-01 00:00:00','2025-06-01 00:00:00','2026-05-08 23:23:19',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`view_count`=VALUES(`view_count`),`like_count`=VALUES(`like_count`),`favorite_count`=VALUES(`favorite_count`),`comment_count`=VALUES(`comment_count`),`published_at`=VALUES(`published_at`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
