UPDATE `blog_topic_article` SET `deleted_at`='2026-05-08 23:23:19',`updated_at`='2026-05-08 23:23:19' WHERE `topic_id` IN (9304001, 9304002, 9304003, 9304004, 9304005, 9304006, 9304007, 9304008);


UPDATE `blog_tag` t SET `use_count` = (SELECT COUNT(*) FROM `blog_article_tag` atg WHERE atg.`tag_name` = t.`name` AND atg.`deleted_at` IS NULL) WHERE t.`name` IN ('Spring', 'Spring Boot', '开发', '开发之CRON表达式', '开发之代码质量', '开发之安全相关', '开发之常用类库', '开发之常见重构技巧', '开发之正则表达式', '开发之网络协议', '开发之随手记', '源码解析');

UPDATE `blog_column` c SET `article_count` = (SELECT COUNT(*) FROM `blog_column_article` ca INNER JOIN `blog_article` a ON a.`id` = ca.`article_id` WHERE ca.`column_id` = c.`id` AND ca.`deleted_at` IS NULL AND a.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED') WHERE c.`id` IN (9200004);

UPDATE `blog_topic` t SET `article_count` = (SELECT COUNT(*) FROM `blog_topic_article` ta INNER JOIN `blog_article` a ON a.`id` = ta.`article_id` WHERE ta.`topic_id` = t.`id` AND ta.`deleted_at` IS NULL AND a.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED') WHERE t.`id` IN (9304001, 9304002, 9304003, 9304004, 9304005, 9304006, 9304007, 9304008);

